var minPairSum = function(nums) {
    nums.sort((a, b) => a - b);
    const n = nums.length;
    let best = 0;
    for (let i = 0; i < n / 2; i++) best = Math.max(best, nums[i] + nums[n - 1 - i]);
    return best;
};
